import{_ as t,C as p,o as l,c as s,a1 as i,E as o}from"./chunks/framework.Clqesclh.js";const f=JSON.parse('{"title":"华山一日游","description":"","frontmatter":{"title":"华山一日游","date":"2023-08-07T02:01:23.000Z"},"headers":[],"relativePath":"posts/huashan.md","filePath":"posts/huashan.md"}'),n={name:"posts/huashan.md"};function r(_,a,c,d,h,m){const e=p("ImageGallery");return l(),s("div",null,[a[0]||(a[0]=i('<p>华山位于陕西省渭南市华阴市，从西安北站坐高铁半小时可达，华山北站离市区大概两公里，市区离徒步登山起点玉泉院大概五公里，可选择住在市里，去景区打车也很方便，景区门票可以提前在小程序“华山旅游服务平台”上预约购买，如果要夜爬，也是先到玉泉院，然后按指示牌指引，绕行一小段路就能进山了，夜间登山沿途都有路灯，比较安全，但如果是第一次来华山，建议还是白天，因为沿途景色很美。</p><p>华山有东南西北中五大主峰，最高峰南峰海拔在 2154.9 米，徒步登山会先到达海拔最低的北峰，然后继续向上遇到岔路口时可选择去其它主峰，看日出在东峰，东峰饭店可以住宿，可选择标间或多人间，最好提前在网上预定。</p><p>这是我第二次来华山，本想夜爬，晚上出高铁站时收到短信说因下雨不让进山，也不能预约购买第二天上午的进山门票，一时不知道该做什么，便一路溜达到城内，在路过第三家烧烤店时没忍住，十个串，一盘凉菜，六瓶啤酒，吃饱喝足后住在边上的酒店。</p><h2 id="时间线" tabindex="-1">时间线 <a class="header-anchor" href="#时间线" aria-label="Permalink to &quot;时间线&quot;">​</a></h2><ul><li><p>7:00 闹钟一响，发现可以预定上午的门票，然后买票、起床、洗漱、吃早饭、在保温杯灌好温水又买了一瓶脉动后打车出发去玉泉院</p></li><li><p>7:50 到达玉泉院，从这里走到华山门后便开始下雨，穿好雨衣继续登山，越往上走雨越大，下半身已经湿透的时候上半身还在出汗，雨水也从小腿流到了鞋里，沿途没有停留休息，后来在快到北峰前的很长一段路上都看不到人，应该是超过了所有在我前面进山的人</p></li><li><p>9:30 到达北峰后找地方避雨，回完微信和电话，处理完公司事情后继续往上走</p></li><li><p>10:30 到达东峰，随后又去了南峰和西峰</p></li><li><p>13:00 左右乘坐西峰索道下山，然后乘坐大巴车回游客中心</p></li><li><p>14:00 左右到达游客中心，因为打不到车于是步行几公里到城里的“文英羊肉泡馍”店吃午饭喝酒，味道不错值得再去，吃完饭还有点时间，然后在市里暴走一段路后溜达到华山北站准备乘车回家</p></li><li><p>18:00 乘坐回北京的高铁，凌晨到家睡觉，第二天上班</p></li></ul>',5)),o(e,{dir:"/images/huashan/"})])}const T=t(n,[["render",r]]);export{f as __pageData,T as default};
